/**
 * DriftOverlayPanel
 *
 * Overlay panel showing drift analysis between actual fleet state and baseline.
 * Displays train drift severity with actionable recommendations.
 *
 * Features:
 * - Drift severity visualization (GREEN, YELLOW, RED)
 * - Per-train mileage drift percentage
 * - Replan recommendations with priority
 * - Filtering by severity level
 *
 * @see specs/006-user-interface.md Section 6.4.3
 */

import {
  Button,
  ButtonGroup,
  Card,
  Collapse,
  Callout,
  HTMLSelect,
  Icon,
  Intent,
  Spinner,
  Tag,
  Tooltip,
} from '@blueprintjs/core';

import { useOverlay, loadDriftOverlayData } from '../../store';
import type { OverlaySliceState, TrainDriftData, DriftSeverity, DriftRecommendation } from '../../store/slices/overlay';

// =============================================================================
// Constants
// =============================================================================

const LAYOUT = {
  PANEL_WIDTH: 320,
  HEADER_HEIGHT: 48,
  TRAIN_ROW_HEIGHT: 44,
  COLLAPSED_HEIGHT: 48,
} as const;

const SEVERITY_COLORS: Record<DriftSeverity, string> = {
  GREEN: '#16A34A',
  YELLOW: '#CA8A04',
  RED: '#DC2626',
};

const SEVERITY_INTENTS: Record<DriftSeverity, typeof Intent[keyof typeof Intent]> = {
  GREEN: Intent.SUCCESS,
  YELLOW: Intent.WARNING,
  RED: Intent.DANGER,
};

const SEVERITY_LABELS: Record<DriftSeverity, string> = {
  GREEN: 'On Track',
  YELLOW: 'Approaching Threshold',
  RED: 'Requires Replan',
};

// =============================================================================
// Helper Functions
// =============================================================================

function formatDriftPct(pct: number): string {
  const sign = pct >= 0 ? '+' : '';
  return `${sign}${pct.toFixed(1)}%`;
}

function getSeverityIcon(severity: DriftSeverity): 'tick-circle' | 'warning-sign' | 'error' {
  switch (severity) {
    case 'GREEN':
      return 'tick-circle';
    case 'YELLOW':
      return 'warning-sign';
    case 'RED':
      return 'error';
    default:
      return 'tick-circle';
  }
}

// =============================================================================
// Sub-Components
// =============================================================================

interface TrainDriftRowProps {
  train: TrainDriftData;
  isExpanded: boolean;
  onToggle: () => void;
  onReplan?: (trainId: string) => void;
}

function TrainDriftRow({ train, isExpanded, onToggle, onReplan }: TrainDriftRowProps) {
  const { trainId, trainNumber, driftSeverity, mileageDriftPct, pmDrifts } = train;

  return (
    <div style={{ marginBottom: 4 }}>
      <div
        onClick={onToggle}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          padding: '10px 12px',
          backgroundColor: isExpanded ? 'var(--pt-intent-warning-5)' : 'var(--pt-app-background-color)',
          borderRadius: 4,
          cursor: 'pointer',
          borderLeft: `3px solid ${SEVERITY_COLORS[driftSeverity]}`,
          transition: 'background-color 0.15s ease',
        }}
      >
        <Icon
          icon={isExpanded ? 'chevron-down' : 'chevron-right'}
          size={12}
          color="var(--pt-text-muted)"
        />

        <Icon
          icon={getSeverityIcon(driftSeverity)}
          size={14}
          intent={SEVERITY_INTENTS[driftSeverity]}
        />

        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 13, fontWeight: 600 }}>
            {trainNumber}
          </div>
          <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
            {SEVERITY_LABELS[driftSeverity]}
          </div>
        </div>

        <Tooltip content={`Mileage drift: ${formatDriftPct(mileageDriftPct)}`} position="left">
          <Tag
            intent={SEVERITY_INTENTS[driftSeverity]}
            minimal={driftSeverity === 'GREEN'}
            style={{ fontFamily: 'monospace', fontSize: 11 }}
          >
            {formatDriftPct(mileageDriftPct)}
          </Tag>
        </Tooltip>
      </div>

      <Collapse isOpen={isExpanded}>
        <div style={{ padding: '12px 12px 12px 28px' }}>
          {/* Drift details */}
          <div style={{ marginBottom: 12 }}>
            <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 4, color: 'var(--pt-text-muted)' }}>
              MILEAGE DRIFT
            </div>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: 8 }}>
              <span style={{ fontSize: 24, fontWeight: 700, color: SEVERITY_COLORS[driftSeverity] }}>
                {formatDriftPct(mileageDriftPct)}
              </span>
              <span style={{ fontSize: 11, color: 'var(--pt-text-muted)' }}>
                from baseline projection
              </span>
            </div>
          </div>

          {/* PM drifts if available */}
          {pmDrifts.length > 0 && (
            <div style={{ marginBottom: 12 }}>
              <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 4, color: 'var(--pt-text-muted)' }}>
                PM SCHEDULE DRIFT
              </div>
              {pmDrifts.map(pm => (
                <div
                  key={pm.pmId}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    padding: '4px 0',
                    fontSize: 11,
                    borderBottom: '1px solid var(--pt-divider-black)',
                  }}
                >
                  <span>PM {pm.pmId.slice(-6)}</span>
                  <span style={{ color: pm.driftDays > 7 ? SEVERITY_COLORS.RED : 'var(--pt-text-muted)' }}>
                    {pm.driftDays > 0 ? '+' : ''}{pm.driftDays} days
                  </span>
                </div>
              ))}
            </div>
          )}

          {/* Actions */}
          {driftSeverity !== 'GREEN' && (
            <div style={{ display: 'flex', gap: 8 }}>
              {driftSeverity === 'RED' && onReplan && (
                <Button
                  intent={Intent.DANGER}
                  icon="refresh"
                  small
                  onClick={() => onReplan(trainId)}
                >
                  Trigger Replan
                </Button>
              )}
              <Button
                minimal
                icon="zoom-to-fit"
                small
              >
                View in Canvas
              </Button>
            </div>
          )}
        </div>
      </Collapse>
    </div>
  );
}

interface RecommendationCardProps {
  recommendation: DriftRecommendation;
  onAction?: (trainId: string) => void;
}

function RecommendationCard({ recommendation, onAction }: RecommendationCardProps) {
  const { trainId, trainNumber, recommendation: rec, reason, priority } = recommendation;
  const priorityIntent = priority === 'HIGH' ? Intent.DANGER : priority === 'MEDIUM' ? Intent.WARNING : Intent.NONE;

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 8,
        padding: '8px 12px',
        backgroundColor: 'var(--pt-app-background-color)',
        borderRadius: 4,
        marginBottom: 4,
        borderLeft: `3px solid ${priority === 'HIGH' ? SEVERITY_COLORS.RED : SEVERITY_COLORS.YELLOW}`,
      }}
    >
      <Icon
        icon={rec === 'REPLAN' ? 'error' : 'eye-open'}
        intent={priorityIntent}
        size={14}
      />
      <div style={{ flex: 1 }}>
        <div style={{ fontSize: 12, fontWeight: 600 }}>
          {trainNumber}: {rec}
        </div>
        <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
          {reason}
        </div>
      </div>
      {rec === 'REPLAN' && onAction && (
        <Button
          intent={Intent.DANGER}
          icon="refresh"
          small
          minimal
          onClick={() => onAction(trainId)}
        />
      )}
    </div>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export interface DriftOverlayPanelProps {
  onClose?: () => void;
  onReplan?: (trainId: string) => void;
}

export function DriftOverlayPanel({ onClose, onReplan }: DriftOverlayPanelProps) {
  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();
  // useScenario() available for baseline selection in future enhancement

  const overlayState = overlayStateRaw as unknown as OverlaySliceState;

  const {
    driftData,
    driftLoading,
    driftError,
    driftSeverityFilter,
    driftExpandedTrains,
    driftRecommendations,
    driftPanelExpanded,
  } = overlayState;

  const handleLoadData = () => {
    loadDriftOverlayData(overlayActions, {});
  };

  const handleSeverityChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const value = event.target.value as DriftSeverity | '';
    overlayActions.setDriftSeverityFilter(value || null);
  };

  const handleToggleTrain = (trainId: string) => {
    overlayActions.toggleDriftTrain(trainId);
  };

  // Filter trains
  const filteredTrains = driftSeverityFilter
    ? driftData?.trains.filter(t => t.driftSeverity === driftSeverityFilter) ?? []
    : driftData?.trains ?? [];

  // Calculate stats
  const stats = {
    total: driftData?.trains.length ?? 0,
    green: driftData?.trains.filter(t => t.driftSeverity === 'GREEN').length ?? 0,
    yellow: driftData?.trains.filter(t => t.driftSeverity === 'YELLOW').length ?? 0,
    red: driftData?.trains.filter(t => t.driftSeverity === 'RED').length ?? 0,
  };

  const highPriorityRecommendations = driftRecommendations.filter(r => r.priority === 'HIGH');

  return (
    <Card
      elevation={2}
      style={{
        position: 'absolute',
        top: 60,
        right: 344,
        width: LAYOUT.PANEL_WIDTH,
        maxHeight: driftPanelExpanded ? 'calc(100vh - 140px)' : LAYOUT.COLLAPSED_HEIGHT,
        overflow: 'hidden',
        transition: 'max-height 0.2s ease',
        zIndex: 20,
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          padding: '12px 16px',
          borderBottom: driftPanelExpanded ? '1px solid var(--pt-divider-black)' : 'none',
          cursor: 'pointer',
        }}
        onClick={() => overlayActions.toggleDriftPanel()}
      >
        <Icon icon="delta" size={16} intent={Intent.WARNING} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 600 }}>Drift Analysis</div>
          {driftData && !driftPanelExpanded && (
            <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
              {stats.red} trains require replan
            </div>
          )}
        </div>
        <Icon
          icon={driftPanelExpanded ? 'chevron-up' : 'chevron-down'}
          size={14}
          color="var(--pt-text-muted)"
        />
        {onClose && (
          <Button
            minimal
            small
            icon="cross"
            onClick={(e) => {
              e.stopPropagation();
              onClose();
            }}
          />
        )}
      </div>

      {driftPanelExpanded && (
        <>
          {/* Controls */}
          <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--pt-divider-black)' }}>
            <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
              <HTMLSelect
                value={driftSeverityFilter || ''}
                onChange={handleSeverityChange}
                style={{ flex: 1 }}
                minimal
              >
                <option value="">All trains</option>
                <option value="RED">Require replan ({stats.red})</option>
                <option value="YELLOW">Approaching ({stats.yellow})</option>
                <option value="GREEN">On track ({stats.green})</option>
              </HTMLSelect>
            </div>

            <ButtonGroup fill>
              <Button
                intent={Intent.PRIMARY}
                icon="refresh"
                onClick={handleLoadData}
                loading={driftLoading}
              >
                {driftData ? 'Refresh' : 'Load Analysis'}
              </Button>
            </ButtonGroup>
          </div>

          {/* Content */}
          <div style={{ padding: '12px 16px', overflow: 'auto', maxHeight: 'calc(100vh - 400px)' }}>
            {driftLoading && !driftData && (
              <div style={{ textAlign: 'center', padding: 24 }}>
                <Spinner size={32} />
                <div style={{ marginTop: 8, color: 'var(--pt-text-muted)' }}>
                  Loading drift analysis...
                </div>
              </div>
            )}

            {driftError && (
              <Callout intent={Intent.DANGER} icon="error">
                {driftError}
              </Callout>
            )}

            {!driftLoading && !driftError && !driftData && (
              <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
                <Icon icon="delta" size={32} style={{ marginBottom: 8, opacity: 0.5 }} />
                <div>Click "Load Analysis" to view drift</div>
              </div>
            )}

            {driftData && (
              <>
                {/* Baseline info */}
                <div style={{ marginBottom: 12, padding: '8px 12px', backgroundColor: 'var(--pt-divider-black)', borderRadius: 4 }}>
                  <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>BASELINE</div>
                  <div style={{ fontSize: 12, fontWeight: 600 }}>{driftData.baselineName}</div>
                </div>

                {/* Summary stats */}
                <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
                  <Tooltip content="Trains on track" position="top">
                    <Tag minimal intent={Intent.SUCCESS} large>
                      <Icon icon="tick-circle" size={12} style={{ marginRight: 4 }} />
                      {stats.green}
                    </Tag>
                  </Tooltip>
                  <Tooltip content="Approaching threshold" position="top">
                    <Tag minimal intent={Intent.WARNING} large>
                      <Icon icon="warning-sign" size={12} style={{ marginRight: 4 }} />
                      {stats.yellow}
                    </Tag>
                  </Tooltip>
                  <Tooltip content="Require replan" position="top">
                    <Tag minimal intent={Intent.DANGER} large>
                      <Icon icon="error" size={12} style={{ marginRight: 4 }} />
                      {stats.red}
                    </Tag>
                  </Tooltip>
                </div>

                {/* High-priority recommendations */}
                {highPriorityRecommendations.length > 0 && (
                  <div style={{ marginBottom: 16 }}>
                    <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 8, color: 'var(--pt-intent-danger)' }}>
                      <Icon icon="warning-sign" size={12} style={{ marginRight: 4 }} />
                      ACTION REQUIRED
                    </div>
                    {highPriorityRecommendations.map(rec => (
                      <RecommendationCard
                        key={rec.trainId}
                        recommendation={rec}
                        onAction={onReplan}
                      />
                    ))}
                  </div>
                )}

                {/* Train list */}
                <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 8, color: 'var(--pt-text-muted)' }}>
                  {driftSeverityFilter ? SEVERITY_LABELS[driftSeverityFilter] : 'ALL TRAINS'}
                  {' '}({filteredTrains.length})
                </div>

                {filteredTrains.map(train => (
                  <TrainDriftRow
                    key={train.trainId}
                    train={train}
                    isExpanded={driftExpandedTrains.includes(train.trainId)}
                    onToggle={() => handleToggleTrain(train.trainId)}
                    onReplan={onReplan}
                  />
                ))}

                {filteredTrains.length === 0 && (
                  <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
                    No trains match the selected filter
                  </div>
                )}
              </>
            )}
          </div>

          {/* Legend */}
          <div
            style={{
              display: 'flex',
              justifyContent: 'center',
              gap: 12,
              padding: '8px 16px',
              borderTop: '1px solid var(--pt-divider-black)',
              fontSize: 10,
            }}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: SEVERITY_COLORS.GREEN }} />
              <span>On Track</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: SEVERITY_COLORS.YELLOW }} />
              <span>Warning</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
              <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: SEVERITY_COLORS.RED }} />
              <span>Replan</span>
            </div>
          </div>
        </>
      )}
    </Card>
  );
}

