/**
 * ScenarioComparisonView
 *
 * Side-by-side comparison view for what-if scenarios against baseline.
 * Allows users to visually compare PM schedules between scenarios.
 *
 * Features:
 * - Split view with baseline on left, scenario on right
 * - Synchronized scrolling between views
 * - Highlighted differences (added, removed, moved PMs)
 * - Summary statistics comparison
 *
 * @see specs/006-user-interface.md Section 6.4.5
 */

import {
  Button,
  ButtonGroup,
  Card,
  HTMLSelect,
  Icon,
  Intent,
  NonIdealState,
  Tag,
} from '@blueprintjs/core';

import { useScenario } from '../../store';
import type { ScenarioSliceState } from '../../store/slices/scenario';

// =============================================================================
// Constants
// =============================================================================

const LAYOUT = {
  MIN_WIDTH: 800,
  HEADER_HEIGHT: 56,
  TOOLBAR_HEIGHT: 48,
  SUMMARY_HEIGHT: 80,
  CANVAS_HEIGHT: 400,
} as const;

const CHANGE_COLORS = {
  ADDED: '#16A34A',
  REMOVED: '#DC2626',
  MOVED: '#2563EB',
  UNCHANGED: '#64748B',
};

// =============================================================================
// Types
// =============================================================================

interface ComparisonDelta {
  pmId: string;
  trainNumber: string;
  pmCode: string;
  changeType: 'ADDED' | 'REMOVED' | 'MOVED' | 'UNCHANGED';
  baselineDate?: string;
  scenarioDate?: string;
  driftDays?: number;
}

interface ComparisonSummary {
  totalChanges: number;
  added: number;
  removed: number;
  moved: number;
  unchanged: number;
  totalCostImpact: number;
  totalManhourImpact: number;
}

// =============================================================================
// Helper Functions
// =============================================================================

function getChangeIcon(changeType: ComparisonDelta['changeType']): 'plus' | 'minus' | 'swap-horizontal' | 'tick' {
  switch (changeType) {
    case 'ADDED':
      return 'plus';
    case 'REMOVED':
      return 'minus';
    case 'MOVED':
      return 'swap-horizontal';
    case 'UNCHANGED':
      return 'tick';
    default:
      return 'tick';
  }
}

function getChangeIntent(changeType: ComparisonDelta['changeType']): typeof Intent[keyof typeof Intent] {
  switch (changeType) {
    case 'ADDED':
      return Intent.SUCCESS;
    case 'REMOVED':
      return Intent.DANGER;
    case 'MOVED':
      return Intent.PRIMARY;
    case 'UNCHANGED':
      return Intent.NONE;
    default:
      return Intent.NONE;
  }
}

function formatCostImpact(cost: number): string {
  if (cost === 0) return '$0';
  const sign = cost > 0 ? '+' : '';
  if (Math.abs(cost) >= 1000000) {
    return `${sign}$${(cost / 1000000).toFixed(1)}M`;
  }
  if (Math.abs(cost) >= 1000) {
    return `${sign}$${(cost / 1000).toFixed(0)}K`;
  }
  return `${sign}$${cost.toFixed(0)}`;
}

// =============================================================================
// Sub-Components
// =============================================================================

interface SummaryCardProps {
  title: string;
  value: string | number;
  intent?: typeof Intent[keyof typeof Intent];
  subtitle?: string;
  icon?: 'changes' | 'dollar' | 'time';
}

function SummaryCard({ title, value, intent, subtitle, icon }: SummaryCardProps) {
  const iconName = icon === 'changes' ? 'changes' : icon === 'dollar' ? 'dollar' : 'time';

  return (
    <div
      style={{
        flex: 1,
        padding: '12px 16px',
        backgroundColor: 'var(--pt-app-background-color)',
        borderRadius: 4,
        textAlign: 'center',
      }}
    >
      <div style={{ fontSize: 10, color: 'var(--pt-text-muted)', marginBottom: 4 }}>
        {icon && <Icon icon={iconName} size={10} style={{ marginRight: 4 }} />}
        {title}
      </div>
      <div
        style={{
          fontSize: 20,
          fontWeight: 700,
          color: intent ? `var(--pt-intent-${intent === Intent.DANGER ? 'danger' : intent === Intent.SUCCESS ? 'success' : 'primary'})` : 'var(--pt-text-color)',
        }}
      >
        {value}
      </div>
      {subtitle && (
        <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
          {subtitle}
        </div>
      )}
    </div>
  );
}

interface DeltaRowProps {
  delta: ComparisonDelta;
  onNavigate?: (pmId: string) => void;
}

function DeltaRow({ delta, onNavigate }: DeltaRowProps) {
  const { pmId, trainNumber, pmCode, changeType, baselineDate, scenarioDate, driftDays } = delta;

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 8,
        padding: '8px 12px',
        borderLeft: `3px solid ${CHANGE_COLORS[changeType]}`,
        backgroundColor: changeType !== 'UNCHANGED' ? 'var(--pt-intent-primary-5)' : 'transparent',
        marginBottom: 2,
        borderRadius: '0 4px 4px 0',
      }}
    >
      <Icon
        icon={getChangeIcon(changeType)}
        intent={getChangeIntent(changeType)}
        size={14}
      />

      <div style={{ flex: 1 }}>
        <div style={{ fontSize: 12, fontWeight: 500 }}>
          {trainNumber} - {pmCode}
        </div>
        <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
          {changeType === 'ADDED' && scenarioDate && `Added: ${scenarioDate}`}
          {changeType === 'REMOVED' && baselineDate && `Removed: ${baselineDate}`}
          {changeType === 'MOVED' && baselineDate && scenarioDate && (
            <>
              {baselineDate} → {scenarioDate}
              {driftDays !== undefined && (
                <span style={{ marginLeft: 4, color: driftDays > 0 ? CHANGE_COLORS.REMOVED : CHANGE_COLORS.ADDED }}>
                  ({driftDays > 0 ? '+' : ''}{driftDays}d)
                </span>
              )}
            </>
          )}
          {changeType === 'UNCHANGED' && baselineDate && `${baselineDate}`}
        </div>
      </div>

      {changeType !== 'UNCHANGED' && (
        <Tag intent={getChangeIntent(changeType)} minimal>
          {changeType}
        </Tag>
      )}

      {onNavigate && (
        <Button
          minimal
          small
          icon="locate"
          onClick={() => onNavigate(pmId)}
        />
      )}
    </div>
  );
}

interface ComparisonCanvasPlaceholderProps {
  title: string;
  data: ComparisonDelta[];
  emptyMessage: string;
}

function ComparisonCanvasPlaceholder({ title, data, emptyMessage }: ComparisonCanvasPlaceholderProps) {
  const changes = data.filter(d => d.changeType !== 'UNCHANGED');

  return (
    <div
      style={{
        flex: 1,
        display: 'flex',
        flexDirection: 'column',
        border: '1px solid var(--pt-divider-black)',
        borderRadius: 4,
        overflow: 'hidden',
      }}
    >
      <div
        style={{
          padding: '8px 12px',
          borderBottom: '1px solid var(--pt-divider-black)',
          backgroundColor: 'var(--pt-divider-black)',
          fontWeight: 600,
          fontSize: 12,
        }}
      >
        {title}
      </div>

      <div style={{ flex: 1, overflow: 'auto', padding: 8 }}>
        {data.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
            {emptyMessage}
          </div>
        ) : (
          data.map(delta => (
            <DeltaRow key={delta.pmId} delta={delta} />
          ))
        )}
      </div>

      <div
        style={{
          padding: '8px 12px',
          borderTop: '1px solid var(--pt-divider-black)',
          backgroundColor: 'var(--pt-divider-black)',
          fontSize: 10,
          display: 'flex',
          gap: 12,
        }}
      >
        <span>{data.length} total PMs</span>
        <span style={{ color: changes.length > 0 ? CHANGE_COLORS.MOVED : 'var(--pt-text-muted)' }}>
          {changes.length} changes
        </span>
      </div>
    </div>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export interface ScenarioComparisonViewProps {
  onClose?: () => void;
  onPromote?: (scenarioId: string) => void;
  onDiscard?: (scenarioId: string) => void;
}

export function ScenarioComparisonView({ onClose, onPromote, onDiscard }: ScenarioComparisonViewProps) {
  const { state: scenarioStateRaw, actions: scenarioActions } = useScenario();

  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;

  const {
    scenarios,
    baselines,
    activeScenarioId,
    isComparing,
    activeDeltas,
    comparisonBaselineId,
  } = scenarioState;

  const activeScenario = scenarios.find(s => s.id === activeScenarioId);
  const activeBaseline = baselines.find(b => b.status === 'PUBLISHED');
  const comparisonBaseline = comparisonBaselineId
    ? baselines.find(b => b.id === comparisonBaselineId)
    : activeBaseline;

  // Build comparison deltas from active scenario deltas
  const mockDeltas: ComparisonDelta[] = activeDeltas.map((d) => ({
    pmId: d.entityId,
    trainNumber: `TR-${d.entityId.slice(-4)}`,
    pmCode: (d.newValues as Record<string, unknown>)?.pmCode as string ?? 'C1',
    changeType: d.deltaType === 'PM_ADD' ? 'ADDED' as const :
                d.deltaType === 'PM_REMOVE' ? 'REMOVED' as const :
                d.deltaType === 'PM_MOVE' ? 'MOVED' as const : 'UNCHANGED' as const,
    baselineDate: d.oldValues ? String((d.oldValues as Record<string, unknown>).targetDate ?? '') : undefined,
    scenarioDate: d.newValues ? String((d.newValues as Record<string, unknown>).targetDate ?? '') : undefined,
    driftDays: d.oldValues && d.newValues ?
      Math.floor((new Date(String((d.newValues as Record<string, unknown>).targetDate ?? '')).getTime() -
                  new Date(String((d.oldValues as Record<string, unknown>).targetDate ?? '')).getTime()) / (1000 * 60 * 60 * 24)) : undefined,
  }));

  const summary: ComparisonSummary = {
    totalChanges: mockDeltas.filter(d => d.changeType !== 'UNCHANGED').length,
    added: mockDeltas.filter(d => d.changeType === 'ADDED').length,
    removed: mockDeltas.filter(d => d.changeType === 'REMOVED').length,
    moved: mockDeltas.filter(d => d.changeType === 'MOVED').length,
    unchanged: mockDeltas.filter(d => d.changeType === 'UNCHANGED').length,
    totalCostImpact: 0, // Would be calculated from deltas in production
    totalManhourImpact: 0, // Would be calculated from deltas in production
  };

  const handleScenarioChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const scenarioId = event.target.value;
    if (scenarioId) {
      scenarioActions.setActiveScenario(scenarioId);
    }
  };

  const handleCompare = () => {
    if (activeScenarioId && activeBaseline) {
      scenarioActions.startComparison({ baselineId: activeBaseline.id });
    }
  };

  const handlePromote = () => {
    if (activeScenarioId && onPromote) {
      onPromote(activeScenarioId);
    }
  };

  const handleDiscard = () => {
    if (activeScenarioId && onDiscard) {
      onDiscard(activeScenarioId);
    }
  };

  // No active scenario
  if (!activeScenario && scenarios.length === 0) {
    return (
      <Card elevation={2} style={{ margin: 16, padding: 24 }}>
        <NonIdealState
          icon="comparison"
          title="No Scenarios"
          description="Create a scenario to compare against the baseline"
          action={
            <Button intent={Intent.PRIMARY} icon="add">
              Create Scenario
            </Button>
          }
        />
        {onClose && (
          <div style={{ position: 'absolute', top: 8, right: 8 }}>
            <Button minimal icon="cross" onClick={onClose} />
          </div>
        )}
      </Card>
    );
  }

  return (
    <div
      style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'var(--pt-app-background-color)',
        zIndex: 30,
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      {/* Header */}
      <div
        style={{
          height: LAYOUT.HEADER_HEIGHT,
          display: 'flex',
          alignItems: 'center',
          gap: 16,
          padding: '0 16px',
          borderBottom: '1px solid var(--pt-divider-black)',
          backgroundColor: 'white',
        }}
      >
        <Icon icon="comparison" size={20} intent={Intent.PRIMARY} />
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 16, fontWeight: 600 }}>Scenario Comparison</div>
          <div style={{ fontSize: 11, color: 'var(--pt-text-muted)' }}>
            Compare what-if scenarios against published baseline
          </div>
        </div>

        <ButtonGroup>
          {activeScenario && (
            <>
              <Button
                intent={Intent.SUCCESS}
                icon="tick"
                onClick={handlePromote}
              >
                Promote
              </Button>
              <Button
                intent={Intent.DANGER}
                icon="trash"
                onClick={handleDiscard}
              >
                Discard
              </Button>
            </>
          )}
          {onClose && (
            <Button minimal icon="cross" onClick={onClose} />
          )}
        </ButtonGroup>
      </div>

      {/* Toolbar */}
      <div
        style={{
          height: LAYOUT.TOOLBAR_HEIGHT,
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          padding: '0 16px',
          borderBottom: '1px solid var(--pt-divider-black)',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 12, color: 'var(--pt-text-muted)' }}>Scenario:</span>
          <HTMLSelect
            value={activeScenarioId || ''}
            onChange={handleScenarioChange}
            minimal
            style={{ minWidth: 200 }}
          >
            <option value="">Select scenario...</option>
            {scenarios.filter(s => s.status === 'ACTIVE').map(scenario => (
              <option key={scenario.id} value={scenario.id}>
                {scenario.name} ({scenario.changeCount} changes)
              </option>
            ))}
          </HTMLSelect>
        </div>

        <Icon icon="arrow-right" size={12} color="var(--pt-text-muted)" />

        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 12, color: 'var(--pt-text-muted)' }}>Baseline:</span>
          <Tag minimal intent={Intent.PRIMARY}>
            {comparisonBaseline?.name ?? 'No baseline'}
          </Tag>
        </div>

        <div style={{ flex: 1 }} />

        <Button
          intent={Intent.PRIMARY}
          icon="comparison"
          onClick={handleCompare}
          disabled={!activeScenarioId || !activeBaseline}
        >
          Compare
        </Button>
      </div>

      {/* Summary */}
      {isComparing && (
        <div
          style={{
            display: 'flex',
            gap: 12,
            padding: 16,
            borderBottom: '1px solid var(--pt-divider-black)',
          }}
        >
          <SummaryCard
            title="TOTAL CHANGES"
            value={summary.totalChanges}
            intent={summary.totalChanges > 0 ? Intent.PRIMARY : Intent.NONE}
            icon="changes"
          />
          <SummaryCard
            title="ADDED"
            value={summary.added}
            intent={summary.added > 0 ? Intent.SUCCESS : Intent.NONE}
          />
          <SummaryCard
            title="REMOVED"
            value={summary.removed}
            intent={summary.removed > 0 ? Intent.DANGER : Intent.NONE}
          />
          <SummaryCard
            title="MOVED"
            value={summary.moved}
            intent={summary.moved > 0 ? Intent.PRIMARY : Intent.NONE}
          />
          <SummaryCard
            title="COST IMPACT"
            value={formatCostImpact(summary.totalCostImpact)}
            intent={summary.totalCostImpact > 0 ? Intent.DANGER : summary.totalCostImpact < 0 ? Intent.SUCCESS : Intent.NONE}
            icon="dollar"
          />
        </div>
      )}

      {/* Comparison content */}
      <div style={{ flex: 1, display: 'flex', gap: 16, padding: 16, overflow: 'hidden' }}>
        {!isComparing && !activeScenarioId && (
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <NonIdealState
              icon="comparison"
              title="Select and Compare"
              description="Select a scenario and click Compare to see differences"
            />
          </div>
        )}

        {isComparing && (
          <>
            <ComparisonCanvasPlaceholder
              title={`Baseline: ${comparisonBaseline?.name ?? 'Published'}`}
              data={mockDeltas.filter(d => d.baselineDate)}
              emptyMessage="No baseline PMs in selected period"
            />
            <ComparisonCanvasPlaceholder
              title={`Scenario: ${activeScenario?.name ?? 'Active'}`}
              data={mockDeltas.filter(d => d.scenarioDate || d.changeType === 'ADDED')}
              emptyMessage="No scenario changes"
            />
          </>
        )}
      </div>
    </div>
  );
}

/**
 * Canvas Layers
 *
 * deck.gl and Konva layers for the infinite canvas.
 * Exports layer components and types for different zoom levels.
 *
 * @see specs/006-user-interface.md Section 6.3
 */

// Types
export * from './types';

// deck.gl Layers (Strategic View - zoom 0-4)
export {
  StrategicHeatmapLayer,
  HeatmapTooltip,
