/**
 * BowWaveIndicator Component
 *
 * Displays bow-wave risk status for maintenance clustering visualization.
 * Bow-wave occurs when PM work accumulates in later periods, causing
 * operational overload and potential service disruptions.
 *
 * This component shows:
 * - Current risk level (LOW/MEDIUM/HIGH/CRITICAL)
 * - Risk score (0-100%)
 * - Peak periods requiring attention
 * - Actionable recommendations
 *
 * @see specs/006-user-interface.md Section 6.5 - Overlay Panels
 * @see specs/004-domain-services.md Section 4.6 - Strategic Planner (bow-wave detection)
 */

import {
  Tag,
  Intent,
  Popover,
  Menu,
  MenuItem,
  MenuDivider,
  ProgressBar,
  Tooltip,
  Spinner,
  Classes,
} from '@blueprintjs/core';

import { useOverlay } from '../store';
import type { OverlaySliceState } from '../store/slices/overlay';
import {
  selectBowWaveRiskDisplay,
  selectBowWavePeakPeriods,
  selectBowWaveHighPriorityRecommendations,
  selectBowWaveSummary,
  loadBowWaveOverlayData,
  type BowWaveRiskLevel,
  type BowWavePeakPeriod,
  type BowWaveRecommendation,
} from '../store/slices/overlay';

// =============================================================================
// Types
// =============================================================================

interface BowWaveIndicatorProps {
  /** Show compact version for toolbar */
  compact?: boolean;
  /** Fleet ID to filter by */
  fleetId?: string;
  /** Plan ID to show specific plan's bow-wave analysis */
  planId?: string;
  /** Custom class name */
  className?: string;
}

// =============================================================================
// Color Mapping
// =============================================================================

const RISK_INTENT_MAP: Record<BowWaveRiskLevel, Intent> = {
  LOW: 'success',
  MEDIUM: 'warning',
  HIGH: 'warning',
  CRITICAL: 'danger',
};

const RISK_ICON_MAP: Record<BowWaveRiskLevel, 'tick-circle' | 'warning-sign' | 'error'> = {
  LOW: 'tick-circle',
  MEDIUM: 'warning-sign',
  HIGH: 'warning-sign',
  CRITICAL: 'error',
};

const RECOMMENDATION_ICON_MAP: Record<BowWaveRecommendation['type'], 'arrow-left' | 'arrow-right' | 'people' | 'horizontal-distribution'> = {
  ADVANCE_PM: 'arrow-left',
  DEFER_PM: 'arrow-right',
  ADD_CAPACITY: 'people',
  SPREAD_WORKLOAD: 'horizontal-distribution',
};

// =============================================================================
// Helper Components
// =============================================================================

function RiskProgressBar({
  riskScore,
  riskLevel,
}: {
  riskScore: number;
  riskLevel: BowWaveRiskLevel;
}) {
  const intent = RISK_INTENT_MAP[riskLevel];

  return (
    <div style={{ marginTop: 8 }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          marginBottom: 4,
          fontSize: 11,
        }}
      >
        <span className={Classes.TEXT_MUTED}>Risk Score</span>
        <span style={{ fontWeight: 500 }}>{Math.round(riskScore * 100)}%</span>
      </div>
      <ProgressBar
        value={riskScore}
        intent={intent}
        stripes={riskLevel === 'CRITICAL'}
        animate={riskLevel === 'CRITICAL'}
      />
    </div>
  );
}

function PeakPeriodItem({ period }: { period: BowWavePeakPeriod }) {
  const intent = RISK_INTENT_MAP[period.riskLevel];

  return (
    <MenuItem
      icon="calendar"
      text={`${period.startQuarter} - ${period.endQuarter}`}
      labelElement={
        <Tag minimal intent={intent}>
          {period.peakLoad} PMs/mo
        </Tag>
      }
    />
  );
}

function RecommendationItem({ rec }: { rec: BowWaveRecommendation }) {
  const priorityIntent: Intent =
    rec.priority === 'HIGH' ? 'danger' : rec.priority === 'MEDIUM' ? 'warning' : 'none';

  return (
    <MenuItem
      icon={RECOMMENDATION_ICON_MAP[rec.type]}
      text={rec.description}
      labelElement={
        <Tag minimal intent={priorityIntent}>
          {rec.priority}
        </Tag>
      }
    />
  );
}

// =============================================================================
// Popover Content
// =============================================================================

function BowWavePopoverContent({
  state,
  onRefresh,
}: {
  state: OverlaySliceState;
  onRefresh: () => void;
}) {
  const riskDisplay = selectBowWaveRiskDisplay(state);
  const peakPeriods = selectBowWavePeakPeriods(state);
  const recommendations = selectBowWaveHighPriorityRecommendations(state);
  const summary = selectBowWaveSummary(state);

  if (state.bowWaveLoading) {
    return (
      <Menu>
        <MenuItem
          disabled
          icon={<Spinner size={16} />}
          text="Loading bow-wave analysis..."
        />
      </Menu>
    );
  }

  if (state.bowWaveError) {
    return (
      <Menu>
        <MenuItem
          disabled
          icon="error"
          intent="danger"
          text={`Error: ${state.bowWaveError}`}
        />
        <MenuDivider />
        <MenuItem icon="refresh" text="Retry" onClick={onRefresh} />
      </Menu>
    );
  }

  if (!state.bowWaveData) {
    return (
      <Menu>
        <MenuItem
          disabled
          icon="info-sign"
          text="No bow-wave data available"
        />
        <MenuDivider />
        <MenuItem icon="refresh" text="Load Analysis" onClick={onRefresh} />
      </Menu>
    );
  }

  const { bowWaveData } = state;

  return (
    <Menu style={{ maxWidth: 400 }}>
      {/* Header with Risk Level */}
      <div style={{ padding: '8px 12px' }}>
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: 8,
          }}
        >
          <span style={{ fontWeight: 600, fontSize: 14 }}>{riskDisplay.label}</span>
          <Tag
            large
            intent={RISK_INTENT_MAP[riskDisplay.level]}
            icon={RISK_ICON_MAP[riskDisplay.level]}
          >
            {riskDisplay.level}
          </Tag>
        </div>

        <RiskProgressBar
          riskScore={bowWaveData.riskScore}
          riskLevel={riskDisplay.level}
        />
      </div>

      <MenuDivider />

      {/* Summary Stats */}
      {summary && (
        <>
          <div style={{ padding: '8px 12px' }}>
            <div className={Classes.TEXT_MUTED} style={{ fontSize: 11, marginBottom: 6 }}>
              Load Distribution
            </div>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: '1fr 1fr',
                gap: 8,
                fontSize: 12,
              }}
            >
              <div>
                <span className={Classes.TEXT_MUTED}>First Half: </span>
                <span style={{ fontWeight: 500 }}>{summary.firstHalfLoad} PMs</span>
              </div>
              <div>
                <span className={Classes.TEXT_MUTED}>Second Half: </span>
                <span style={{ fontWeight: 500 }}>{summary.secondHalfLoad} PMs</span>
              </div>
              <div>
                <span className={Classes.TEXT_MUTED}>Imbalance: </span>
                <span
                  style={{
                    fontWeight: 500,
                    color:
                      summary.loadImbalanceRatio > 1.5
                        ? '#DC2626'
                        : summary.loadImbalanceRatio > 1.2
                          ? '#F59E0B'
                          : '#10B981',
                  }}
                >
                  {summary.loadImbalanceRatio.toFixed(2)}x
                </span>
              </div>
              <div>
                <span className={Classes.TEXT_MUTED}>Total: </span>
                <span style={{ fontWeight: 500 }}>{summary.totalPms} PMs</span>
              </div>
            </div>
          </div>
          <MenuDivider />
        </>
      )}

      {/* Peak Periods */}
      {peakPeriods.length > 0 && (
        <>
          <MenuItem disabled text="Peak Periods" icon="timeline-events" />
          {peakPeriods.slice(0, 3).map((period, idx) => (
            <PeakPeriodItem key={idx} period={period} />
          ))}
          {peakPeriods.length > 3 && (
            <MenuItem
              disabled
              text={`... and ${peakPeriods.length - 3} more`}
              className={Classes.TEXT_MUTED}
            />
          )}
          <MenuDivider />
        </>
      )}

      {/* Recommendations */}
      {recommendations.length > 0 && (
        <>
          <MenuItem disabled text="Recommendations" icon="lightbulb" />
          {recommendations.slice(0, 3).map((rec, idx) => (
            <RecommendationItem key={idx} rec={rec} />
          ))}
          {recommendations.length > 3 && (
            <MenuItem
              disabled
              text={`... and ${recommendations.length - 3} more`}
              className={Classes.TEXT_MUTED}
            />
          )}
          <MenuDivider />
        </>
      )}

      {/* Actions */}
      <MenuItem icon="refresh" text="Refresh Analysis" onClick={onRefresh} />
      <MenuItem icon="chart" text="View Full Report" />
    </Menu>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export function BowWaveIndicator({
  compact = false,
  fleetId,
  planId,
  className,
}: BowWaveIndicatorProps) {
  const { state: rawState, actions } = useOverlay();
  const state = rawState as unknown as OverlaySliceState;

  // Load data callback
  const loadData = () => {
    loadBowWaveOverlayData(
      {
        setBowWaveLoading: actions.setBowWaveLoading,
        setBowWaveData: actions.setBowWaveData,
        setBowWaveError: actions.setBowWaveError,
      },
      { fleetId, planId }
    );
  };

  // Auto-load data on initial render if never loaded
  // Check in render is safe because we're using slice state to track load status
  const shouldAutoLoad =
    state.bowWaveLastFetch === null &&
    !state.bowWaveLoading &&
    state.bowWaveData === null;

  if (shouldAutoLoad) {
    // Defer load to next microtask to avoid state updates during render
    Promise.resolve().then(loadData);
  }

  const riskDisplay = selectBowWaveRiskDisplay(state);
  const intent = RISK_INTENT_MAP[riskDisplay.level];
  const icon = RISK_ICON_MAP[riskDisplay.level];

  // Loading state
  if (state.bowWaveLoading && !state.bowWaveData) {
    return (
      <Tag minimal className={className}>
        <Spinner size={12} />
        <span style={{ marginLeft: 6 }}>Loading...</span>
      </Tag>
    );
  }

  // Compact version for toolbar
  if (compact) {
    return (
      <Popover
        content={<BowWavePopoverContent state={state} onRefresh={loadData} />}
        placement="bottom"
        interactionKind="hover"
        hoverOpenDelay={200}
      >
        <Tooltip content={riskDisplay.label} placement="bottom">
          <Tag
            intent={intent}
            icon={icon}
            interactive
            className={className}
            style={{ cursor: 'pointer' }}
          >
            {state.bowWaveData
              ? `${Math.round(state.bowWaveData.riskScore * 100)}%`
              : 'N/A'}
          </Tag>
        </Tooltip>
      </Popover>
    );
  }

  // Full version for status bar
  return (
    <Popover
      content={<BowWavePopoverContent state={state} onRefresh={loadData} />}
      placement="top"
      interactionKind="hover"
      hoverOpenDelay={200}
    >
      <Tag
        intent={intent}
        icon={icon}
        interactive
        className={className}
        style={{ cursor: 'pointer' }}
      >
        {riskDisplay.label}
        {state.bowWaveData && (
          <span style={{ marginLeft: 6, opacity: 0.8 }}>
            ({Math.round(state.bowWaveData.riskScore * 100)}%)
          </span>
        )}
      </Tag>
    </Popover>
  );
}

export default BowWaveIndicator;

/**
 * Keyboard Shortcuts Dialog
 *
 * Displays the list of keyboard shortcuts available in the MMS canvas.
 * Triggered by pressing '?' or from the Help menu.
 *
 * @see specs/006-user-interface.md Section 6.9.2
 */

import { Dialog, Classes, HTMLTable, Tag, Intent } from '@blueprintjs/core';
import { useUi } from '../store';
import type { UiSliceState } from '../store/slices/ui';

/**
 * Keyboard shortcut definition
 */
interface ShortcutDefinition {
  key: string;
  description: string;
  category: 'navigation' | 'zoom' | 'selection' | 'editing' | 'general';
}

/**
 * All keyboard shortcuts per spec 006.9.2
 */
const KEYBOARD_SHORTCUTS: ShortcutDefinition[] = [
  // Navigation shortcuts
  { key: 'Arrow keys', description: 'Pan canvas', category: 'navigation' },
  { key: 'Home', description: 'Go to today', category: 'navigation' },
  { key: 't', description: 'Go to today', category: 'navigation' },
  { key: 'Tab', description: 'Navigate between panels', category: 'navigation' },
  { key: 'Shift+Tab', description: 'Navigate between panels (reverse)', category: 'navigation' },

  // Zoom shortcuts
  { key: '+', description: 'Zoom in', category: 'zoom' },
  { key: '-', description: 'Zoom out', category: 'zoom' },
  { key: '1', description: 'Strategic view (12-year)', category: 'zoom' },
  { key: '2', description: 'Tactical-wide view (1-year)', category: 'zoom' },
  { key: '3', description: 'Tactical view (12-week)', category: 'zoom' },
  { key: '4', description: 'Operational view (4-week)', category: 'zoom' },
  { key: '5', description: 'Detail view (1-week)', category: 'zoom' },
  { key: 's', description: 'Strategic view', category: 'zoom' },
  { key: 'o', description: 'Operational view', category: 'zoom' },

  // Selection shortcuts
  { key: 'Enter', description: 'Activate selected element', category: 'selection' },
  { key: 'Space', description: 'Toggle selection', category: 'selection' },
  { key: 'Escape', description: 'Cancel drag / Close dialog / Deselect', category: 'selection' },

  // Editing shortcuts
  { key: 'l', description: 'Lock/unlock selected PM', category: 'editing' },
  { key: 'Delete', description: 'Cancel selected PM (with confirmation)', category: 'editing' },

  // General shortcuts
  { key: '?', description: 'Show keyboard shortcuts (this dialog)', category: 'general' },
];

/**
 * Category labels and order
 */
const CATEGORIES: { id: ShortcutDefinition['category']; label: string }[] = [
  { id: 'navigation', label: 'Navigation' },
  { id: 'zoom', label: 'Zoom & Views' },
  { id: 'selection', label: 'Selection' },
  { id: 'editing', label: 'Editing' },
  { id: 'general', label: 'General' },
];

/**
 * Shortcut key badge component
 */
function KeyBadge({ keyName }: { keyName: string }) {
  const parts = keyName.split('+');
  return (
    <span style={{ display: 'inline-flex', gap: '4px', alignItems: 'center' }}>
      {parts.map((part, index) => (
        <span key={index}>
          <Tag minimal style={{ fontFamily: 'monospace', fontWeight: 600, fontSize: '12px' }}>
            {part.trim()}
          </Tag>
          {index < parts.length - 1 && <span style={{ margin: '0 2px', color: '#5c7080' }}>+</span>}
        </span>
      ))}
    </span>
  );
}

/**
 * Shortcuts table for a category
 */
function ShortcutCategory({
  category,
  shortcuts,
}: {
  category: { id: string; label: string };
  shortcuts: ShortcutDefinition[];
}) {
  return (
    <div style={{ marginBottom: '20px' }}>
      <h4 style={{ margin: '0 0 8px 0', color: '#5c7080', fontSize: '13px', fontWeight: 600 }}>
        {category.label}
      </h4>
      <HTMLTable
        compact
        striped
        style={{ width: '100%', fontSize: '13px' }}
      >
        <tbody>
          {shortcuts.map((shortcut) => (
            <tr key={shortcut.key}>
              <td style={{ width: '140px', paddingRight: '16px' }}>
                <KeyBadge keyName={shortcut.key} />
              </td>
              <td>{shortcut.description}</td>
            </tr>
          ))}
        </tbody>
      </HTMLTable>
    </div>
  );
}

/**
 * Keyboard Shortcuts Dialog Component
 *
 * Displays all available keyboard shortcuts organized by category.
 * Uses @belt/tools state management for dialog visibility.
 */
export function KeyboardShortcutsDialog() {
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const uiState = uiStateRaw as unknown as UiSliceState;

  const handleClose = () => {
    uiActions.hideKeyboardShortcutsDialog();
  };

  // Group shortcuts by category
  const shortcutsByCategory = CATEGORIES.map((category) => ({
    category,
    shortcuts: KEYBOARD_SHORTCUTS.filter((s) => s.category === category.id),
  })).filter(({ shortcuts }) => shortcuts.length > 0);

  return (
    <Dialog
      isOpen={uiState.keyboardShortcutsDialogOpen}
      onClose={handleClose}
      title="Keyboard Shortcuts"
      icon="key-command"
      style={{ width: '520px' }}
    >
      <div className={Classes.DIALOG_BODY} style={{ maxHeight: '60vh', overflowY: 'auto' }}>
        <p style={{ marginTop: 0, marginBottom: '20px', color: '#5c7080', fontSize: '13px' }}>
          These keyboard shortcuts help you navigate and interact with the PM schedule canvas efficiently.
        </p>

        {shortcutsByCategory.map(({ category, shortcuts }) => (
          <ShortcutCategory
            key={category.id}
            category={category}
            shortcuts={shortcuts}
          />
        ))}

        <div style={{ marginTop: '16px', padding: '12px', backgroundColor: '#f5f8fa', borderRadius: '4px' }}>
          <Tag intent={Intent.PRIMARY} minimal style={{ marginRight: '8px' }}>
            Tip
          </Tag>
          <span style={{ fontSize: '12px', color: '#5c7080' }}>
            Press <KeyBadge keyName="Escape" /> to close this dialog or any modal.
            Shortcuts are disabled when typing in input fields.
          </span>
        </div>
      </div>

      <div className={Classes.DIALOG_FOOTER}>
        <div className={Classes.DIALOG_FOOTER_ACTIONS}>
          <Tag minimal style={{ marginRight: 'auto', color: '#5c7080' }}>
            {uiState.shortcutsEnabled ? 'Shortcuts enabled' : 'Shortcuts disabled'}
          </Tag>
        </div>
      </div>
    </Dialog>
  );
}

/**
 * Export keyboard shortcuts constant for testing
 */
export { KEYBOARD_SHORTCUTS };

/**
 * Drag Confirmation Dialog
 *
 * Modal dialog for confirming PM reschedule operations.
 * Shows impact assessment and allows user to confirm or cancel.
 *
 * @see specs/006-user-interface.md Section 6.3.4
 */

import {
  Dialog,
  DialogBody,
  DialogFooter,
  Button,
  Intent,
  Callout,
  Spinner,
  Tag,
  Icon,
} from '@blueprintjs/core';

import type { PmMoveImpact, DragConstraintViolation } from './layers/types';

// =============================================================================
// Types
// =============================================================================

export interface DragConfirmationDialogProps {
  isOpen: boolean;
  pmCode: string;
  trainNumber: string;
  sourceDate: string;
  targetDate: string;
  impact: PmMoveImpact | null;
  violations: DragConstraintViolation[];
  isLoading: boolean;
  onConfirm: () => void;
  onCancel: () => void;
}

// =============================================================================
// Component
// =============================================================================

export function DragConfirmationDialog({
  isOpen,
  pmCode,
  trainNumber,
  sourceDate,
  targetDate,
  impact,
  violations,
  isLoading,
  onConfirm,
  onCancel,
}: DragConfirmationDialogProps) {
  const hasErrors = violations.some(v => v.severity === 'ERROR');
  const hasWarnings = violations.some(v => v.severity === 'WARNING');

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const daysDiff = Math.round(
    (new Date(targetDate).getTime() - new Date(sourceDate).getTime()) / (1000 * 60 * 60 * 24)
  );

  return (
    <Dialog
      isOpen={isOpen}
      onClose={onCancel}
      title="Confirm PM Reschedule"
      icon="calendar"
      canEscapeKeyClose={!isLoading}
      canOutsideClickClose={!isLoading}
    >
      <DialogBody>
        {/* PM Info Header */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px',
          marginBottom: '16px',
          padding: '12px',
          backgroundColor: 'var(--pt-app-secondary-background-color, #f5f8fa)',
          borderRadius: '6px',
        }}>
          <Icon icon="wrench" size={24} color="var(--pt-icon-color)" />
          <div>
            <div style={{ fontWeight: 600, fontSize: '16px' }}>
              {pmCode}
            </div>
            <div style={{ color: 'var(--pt-text-muted)', fontSize: '13px' }}>
              Train {trainNumber}
            </div>
          </div>
        </div>

        {/* Date Change Summary */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '16px',
          marginBottom: '20px',
          padding: '16px',
          backgroundColor: 'var(--pt-app-background-color)',
          border: '1px solid var(--pt-divider-black)',
          borderRadius: '6px',
        }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
              FROM
            </div>
            <div style={{ fontWeight: 600 }}>
              {formatDate(sourceDate)}
            </div>
          </div>

          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            padding: '8px 12px',
            backgroundColor: daysDiff > 0 ? '#fff3cd' : '#d4edda',
            borderRadius: '4px',
          }}>
            <Icon
              icon={daysDiff > 0 ? 'arrow-right' : 'arrow-left'}
              color={daysDiff > 0 ? '#856404' : '#155724'}
            />
            <span style={{
              fontWeight: 600,
              color: daysDiff > 0 ? '#856404' : '#155724',
            }}>
              {Math.abs(daysDiff)} day{Math.abs(daysDiff) !== 1 ? 's' : ''} {daysDiff > 0 ? 'later' : 'earlier'}
            </span>
          </div>

          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
              TO
            </div>
            <div style={{ fontWeight: 600 }}>
              {formatDate(targetDate)}
            </div>
          </div>
        </div>

        {/* Violations */}
        {violations.length > 0 && (
          <div style={{ marginBottom: '16px' }}>
            {violations.filter(v => v.severity === 'ERROR').map((violation, i) => (
              <Callout
                key={i}
                intent={Intent.DANGER}
                icon="error"
                style={{ marginBottom: '8px' }}
              >
                <strong>{violation.type.replace(/_/g, ' ')}</strong>
                <div style={{ marginTop: '4px' }}>{violation.message}</div>
              </Callout>
            ))}
            {violations.filter(v => v.severity === 'WARNING').map((violation, i) => (
              <Callout
                key={i}
                intent={Intent.WARNING}
                icon="warning-sign"
                style={{ marginBottom: '8px' }}
              >
                <strong>{violation.type.replace(/_/g, ' ')}</strong>
                <div style={{ marginTop: '4px' }}>{violation.message}</div>
              </Callout>
            ))}
          </div>
        )}

        {/* Impact Assessment */}
        {isLoading ? (
          <div style={{ textAlign: 'center', padding: '24px' }}>
            <Spinner size={24} />
            <div style={{ marginTop: '8px', color: 'var(--pt-text-muted)' }}>
              Calculating impact...
            </div>
          </div>
        ) : impact ? (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(2, 1fr)',
            gap: '12px',
            marginTop: '16px',
          }}>
            {/* Man-hour Impact */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                MAN-HOUR IMPACT
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                <span style={{ fontSize: '12px' }}>Source Week:</span>
                <Tag minimal>
                  {impact.manhourChange.sourceWeek.required}h / {impact.manhourChange.sourceWeek.available}h
                </Tag>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontSize: '12px' }}>Target Week:</span>
                <Tag
                  minimal
                  intent={impact.manhourChange.targetWeek.required > impact.manhourChange.targetWeek.available
                    ? Intent.DANGER
                    : Intent.NONE
                  }
                >
                  {impact.manhourChange.targetWeek.required}h / {impact.manhourChange.targetWeek.available}h
                </Tag>
              </div>
            </div>

            {/* Cost Impact */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                COST IMPACT
              </div>
              <div style={{
                fontSize: '18px',
                fontWeight: 600,
                color: impact.costChange > 0 ? '#d9534f' : impact.costChange < 0 ? '#5cb85c' : 'inherit',
              }}>
                {impact.costChange > 0 ? '+' : ''}{impact.costChange.toFixed(2)} HKD
              </div>
            </div>

            {/* Baseline Drift */}
            <div style={{
              padding: '12px',
              backgroundColor: 'var(--pt-app-secondary-background-color)',
              borderRadius: '6px',
            }}>
              <div style={{
                fontSize: '11px',
                fontWeight: 600,
                color: 'var(--pt-text-muted)',
                marginBottom: '8px',
              }}>
                BASELINE DRIFT
              </div>
              <div style={{
                fontSize: '18px',
                fontWeight: 600,
                color: Math.abs(impact.driftFromBaseline) > 7 ? '#d9534f' : 'inherit',
              }}>
                {impact.driftFromBaseline > 0 ? '+' : ''}{impact.driftFromBaseline} days
              </div>
            </div>

            {/* Conflicts */}
            {impact.conflictsCreated.length > 0 && (
              <div style={{
                padding: '12px',
                backgroundColor: '#fff3cd',
                borderRadius: '6px',
              }}>
                <div style={{
                  fontSize: '11px',
                  fontWeight: 600,
                  color: '#856404',
                  marginBottom: '8px',
                }}>
                  CONFLICTS CREATED
                </div>
                {impact.conflictsCreated.map((conflict, i) => (
                  <Tag key={i} intent={Intent.WARNING} minimal style={{ marginRight: '4px', marginBottom: '4px' }}>
                    {conflict}
                  </Tag>
                ))}
              </div>
            )}
          </div>
        ) : null}
      </DialogBody>

      <DialogFooter
        actions={
          <>
            <Button
              onClick={onCancel}
              disabled={isLoading}
            >
              Cancel
            </Button>
            <Button
              intent={hasErrors ? Intent.DANGER : hasWarnings ? Intent.WARNING : Intent.PRIMARY}
              onClick={onConfirm}
              disabled={isLoading || hasErrors}
              icon={hasWarnings ? 'warning-sign' : 'tick'}
            >
              {hasErrors ? 'Cannot Reschedule' : hasWarnings ? 'Reschedule Anyway' : 'Confirm Reschedule'}
            </Button>
          </>
        }
      />
    </Dialog>
  );
}

export default DragConfirmationDialog;

